_log = []
_initialized = False
_buffer = []


def reset():
    global _initialized
    _log.clear()
    _buffer.clear()
    _initialized = False


def _flush_buffer():
    while _buffer:
        item = _buffer.pop(0)
        _log.append(f"processed:{item}")


def init():
    global _initialized
    _initialized = True
    _log.append("init")
    _flush_buffer()


def process(item):
    """Process items in arrival order, even if init() has not run yet."""
    if not _initialized:
        _buffer.append(item)
        _log.append(f"buffered:{item}")
        return True
    _log.append(f"processed:{item}")
    return True


